async (params, browser) => {
  // Open user profile
  await browser.open(`https://github.com/${params.username}`)

  // Wait for profile page
  await browser.waitForSelector('.vcard-fullname, [itemprop=\'name\'], .js-profile-editable-area, .h-card', 15000)

  // Let page render
  await browser.wait(2000)

  // Extract profile data
  const result = await browser.evaluate(`const name = document.querySelector('.vcard-fullname, [itemprop="name"], .p-name')?.textContent?.trim() || ''; const login = document.querySelector('.vcard-username, [itemprop="additionalName"], .p-nickname')?.textContent?.trim() || window.location.pathname.substring(1); const bio = document.querySelector('[data-bio-text], .user-profile-bio, [itemprop="description"], .p-note')?.textContent?.trim() || ''; const company = document.querySelector('[itemprop="worksFor"], .p-org')?.textContent?.trim() || ''; const location = document.querySelector('[itemprop="homeLocation"], .p-label')?.textContent?.trim() || ''; const navLinks = document.querySelectorAll('nav a, a[data-tab]'); let followersText = ''; let followingText = ''; let reposText = ''; for (const link of navLinks) { const href = link.getAttribute('href') || ''; const text = link.textContent.trim(); if (href.includes('followers')) followersText = text.replace(/[^\d.kKmM]/g, ''); if (href.includes('following')) followingText = text.replace(/[^\d.kKmM]/g, ''); if (href.includes('tab=repositories')) reposText = text.replace(/[^\d.kKmM]/g, ''); } if (!followersText) { const f = document.querySelector('a[href*="followers"] span, a[href*="followers"]'); followersText = f ? f.textContent.trim().replace(/[^\d.kKmM]/g, '') : ''; } if (!followingText) { const f = document.querySelector('a[href*="following"] span, a[href*="following"]'); followingText = f ? f.textContent.trim().replace(/[^\d.kKmM]/g, '') : ''; } const pinned = Array.from(document.querySelectorAll('.pinned-item-list-item, [data-testid="pinned-item"], .js-pinned-items-reorder-container li')).map(p => { const nameEl = p.querySelector('.repo, a span.repo, a[href] span'); const descEl = p.querySelector('p.pinned-item-desc, p.mb-2, p'); const langEl = p.querySelector('[itemprop="programmingLanguage"]'); const starsEl = p.querySelector('a[href*="/stargazers"] span, svg.octicon-star'); const starsText = starsEl ? (starsEl.closest('a') || starsEl.parentElement)?.textContent?.trim() || '' : ''; return { name: nameEl?.textContent?.trim() || '', description: descEl?.textContent?.trim() || '', language: langEl?.textContent?.trim() || '', stars: starsText.replace(/[^\d.kKmM]/g, '') }; }).filter(p => p.name); return { name: name, username: login, bio: bio, company: company, location: location, followers: followersText, following: followingText, public_repos: reposText, pinned_repos: pinned, url: window.location.href }`)

  return result
}
